"use strict";(globalThis.webpackChunkgsf_docusaurus_template=globalThis.webpackChunkgsf_docusaurus_template||[]).push([[3027],{1014(e){e.exports=JSON.parse('{"tag":{"label":"size:large","permalink":"/gsf-patterns/tags/size-large","allTagsPath":"/gsf-patterns/tags","count":3,"items":[{"id":"architecture/system-topology/run-ai-models-edge","title":"Run AI models at the edge","description":"Deploy AI inference on edge devices or local infrastructure to reduce data transfer, network energy use, and reliance on centralised cloud compute.","permalink":"/gsf-patterns/architecture/system-topology/run-ai-models-edge"},{"id":"requirements/shed-lower-priority-traffic","title":"Shed lower priority traffic","description":"When resources are constrained during high-traffic events or when carbon intensity is high, more carbon emissions will be generated from your system. Adding more resources to support increased traffic requirements introduces more embodied carbon and more demand for electricity. Continuing to handle all requests during high carbon intensity will increase overall emissions for your system. Shedding traffic that is lower priority during these scenarios will save on resources and carbon emissions. This approach requires an understanding of your traffic, including which call requests are critical and which can best withstand retry attempts and failures.","permalink":"/gsf-patterns/requirements/shed-lower-priority-traffic"},{"id":"operations/carbon-aware-ai-scheduling","title":"Use carbon-aware scheduling and region selection for AI workloads","description":"Reduce the carbon impact of AI workloads by running them in cloud regions with lower grid carbon intensity and scheduling deferrable jobs during periods of high renewable energy availability.","permalink":"/gsf-patterns/operations/carbon-aware-ai-scheduling"}],"unlisted":false}}')}}]);